if (/^https?:\/\/|^git@|^git\+/.test(ref)) {
  const cleanRef = ref.replace(/^git\+/, '');
  const tmpBase = path.join(require('os').tmpdir(), `gad-try-clone-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`);
