    for (const name of fs.readdirSync(skillsDirCandidate)) {
      candidates.push(path.join(skillsDirCandidate, name, 'SKILL.md'));
      candidates.push(path.join(skillsDirCandidate, name, 'skill.md'));
    }
  }
  const found = candidates.find((c) => fs.existsSync(c));
  if (!found) {
    fs.rmSync(tmpBase, { recursive: true, force: true });
    throw new Error(`no SKILL.md found in ${cleanRef} at any of: ${candidates.map((c) => path.relative(tmpBase, c)).join(', ')}`);
  }
  return {
    kind: 'git-url',
    sourceDir: path.dirname(found),
    slug,
    source: cleanRef,
    cleanup: () => {
      try { fs.rmSync(tmpBase, { recursive: true, force: true }); } catch {}
    },
  };
}

