        const va = parseInt(a.version.replace("v", ""), 10);
        const vb = parseInt(b.version.replace("v", ""), 10);
        return vb - va;
      });
    return {
      species: sp.species ?? sp.workflow ?? "default",
      contextFramework: sp.contextFramework,
      runs,
      latest: runs[0] ?? null,
