let pdfParse = null;
function getPdfParser() {
  if (pdfParse === null) {
    try {
      pdfParse = require('pdf-parse');
    } catch {
      pdfParse = false; // Mark as unavailable
    }
  }
  return pdfParse || null;
}

/**
