    );
  }

  return (
    <div className="overflow-y-auto h-full">
      <ProjectCanvas
        project={project}
        projectDisplayName={projectDisplayName}
        allProjects={allProjects}
        allRuns={allRuns}
        selection={selection}
        onSelect={setSelection}
      />
    </div>
  );
};

