"use client";

import { useState } from "react";
import { SiteSection } from "@/components/site";
import { cn } from "@/lib/utils";

type DiffKind = "added" | "removed" | "modified" | "unchanged";

type DiffNode = {
  keyPath: string;
  key: string;
  kind: DiffKind;
  before?: unknown;
  after?: unknown;
  delta?: number | null;
  children?: DiffNode[];
};

function diffObjects(
  before: Record<string, unknown>,
  after: Record<string, unknown>,
  prefix = "",
): DiffNode[] {
  const allKeys = new Set([...Object.keys(before), ...Object.keys(after)]);
  const nodes: DiffNode[] = [];

  for (const key of allKeys) {
    const keyPath = prefix ? `${prefix}.${key}` : key;
    const bVal = before[key];
    const aVal = after[key];

    if (!(key in before)) {
      nodes.push({ keyPath, key, kind: "added", after: aVal });
    } else if (!(key in after)) {
      nodes.push({ keyPath, key, kind: "removed", before: bVal });
    } else if (
      bVal !== null &&
      aVal !== null &&
      typeof bVal === "object" &&
      typeof aVal === "object" &&
      !Array.isArray(bVal) &&
      !Array.isArray(aVal)
    ) {
      const children = diffObjects(
        bVal as Record<string, unknown>,
        aVal as Record<string, unknown>,
        keyPath,
      );
      const hasChanges = children.some((c) => c.kind !== "unchanged");
      nodes.push({
        keyPath,
        key,
        kind: hasChanges ? "modified" : "unchanged",
